previewCss:
.darma-loader-darma-custom-673__cube-loader {color: var(--loader-color, #14b8a6);

  position: relative;
  width: 75px;
  height: 75px;
  transform-style: preserve-3d;
  transform: rotateX(-30deg);
  animation: darma-loader-darma-custom-673-cubeSpin var(--loader-speed, 4s) linear infinite;
}
@keyframes darma-loader-darma-custom-673-cubeSpin {
  0% { transform: rotateX(-30deg) rotateY(0); }
  100% { transform: rotateX(-30deg) rotateY(360deg); }
}
.darma-loader-darma-custom-673__cube-loader .darma-loader-darma-custom-673__cube-wrapper {
  position: absolute;
  inset: 0;
  transform-style: preserve-3d;
}
.darma-loader-darma-custom-673__cube-loader .darma-loader-darma-custom-673__cube-wrapper .darma-loader-darma-custom-673__cube-span {
  position: absolute;
  inset: 0;
  transform: rotateY(calc(90deg * var(--i))) translateZ(37.5px);
  background: linear-gradient(to bottom, #323232, var(--loader-color, #14b8a6), var(--loader-secondary-color, #67e8f9));
}
.darma-loader-darma-custom-673__cube-top {
  position: absolute;
  width: 75px;
  height: 75px;
  background: #323232;
  transform: rotateX(90deg) translateZ(37.5px);
  transform-style: preserve-3d;
}
.darma-loader-darma-custom-673__cube-top::before {
  content: "";
  position: absolute;
  width: 75px;
  height: 75px;
  background: var(--loader-color, #14b8a6);
  transform: translateZ(-90px);
  filter: blur(10px);
  box-shadow: 0 0 10px #323232, 0 0 24px var(--loader-color, #14b8a6), 0 0 40px var(--loader-secondary-color, #67e8f9);
}

